#include <queue>

queue<int> q;

q.push(10); // added at the back
q.push(20);
q.push(30);

cout << q.front(); // 10 — the oldest element, first to leave
cout << q.back();  // 30 — the newest element, most recently added

q.pop(); // removes from the FRONT (10) — note: pop() returns nothing, same as stack

#include <iostream>
#include <queue>

using namespace std;

int main()
{
    queue<int> q;
    q.push(10);
    q.push(20);
    q.push(30);

    while (!q.empty())
    {
        cout << q.front() << " ";
        q.pop();
    }

    return 0;
}

